## 3. 쿼리 최적화 및 인덱스 전략

### 3-1. 핵심 인덱스 정의

```sql
-- matching_queue 테이블
ALTER TABLE maum.matching_queue
  ADD INDEX idx_status_waiting_since (status, waiting_since),
  ADD INDEX idx_user_status (user_id, status);

-- user_profile 테이블 (매칭 필터 조건)
ALTER TABLE maum.user_profile
  ADD INDEX idx_gender_age (gender, age_group);

-- call_history 테이블
ALTER TABLE maum.call_history
  ADD INDEX idx_user_created (user_id, created_at DESC);
```

### 3-2. 매칭 서비스 전체 개선 흐름

```kotlin
// MatchingService.kt (개선 후 전체)
@Service
@Transactional
class MatchingService(
    private val queueRedis: MatchingQueueRedisRepository,
    private val profileCache: UserProfileCacheService,
    private val matchingQueueRepository: MatchingQueueRepository,
    private val callRoomRepository: CallRoomRepository
) {

    fun joinQueue(userId: String): JoinQueueResult {
        // 1단계: Redis 원자적 중복 방지 (DB 조회 없음)
        val joined = queueRedis.joinQueue(userId)
        if (!joined) return JoinQueueResult.AlreadyWaiting

        // 2단계: DB 영구 기록 (비동기 처리 가능)
        matchingQueueRepository.save(
            MatchingQueueEntity(userId = userId)
        )
        return JoinQueueResult.Joined
    }

    fun tryMatch(requesterId: String): MatchingResult {
        // 1단계: Redis에서 O(log N)으로 후보 추출
        val candidateId = queueRedis.popOldestCandidate() ?: return MatchingResult.NoCandidate
        if (candidateId == requesterId) {
            // 본인이 팝된 경우 재삽입
            queueRedis.joinQueue(candidateId)
            return MatchingResult.NoCandidate
        }

        // 2단계: 캐시에서 프로필 조회 (DB 미접근)
        val requesterProfile = profileCache.getProfile(requesterId)
        val candidateProfile = profileCache.getProfile(candidateId)

        // 3단계: 필터 조건 검증 (메모리에서 처리)
        if (!isCompatible(requesterProfile, candidateProfile)) {
            queueRedis.joinQueue(candidateId)  // 미매칭 시 재삽입
            return MatchingResult.NoCandidate
        }

        // 4단계: 통화방 생성
        val callRoom = callRoomRepository.save(
            CallRoomEntity(
                requesterId = requesterId,
                responderId = candidateId
            )
        )
        queueRedis.leaveQueue(requesterId)

        return MatchingResult.Matched(callRoom.id, candidateId)
    }

    private fun isCompatible(a: UserProfileDto, b: UserProfileDto): Boolean {
        return (a.preferredGender == b.gender || a.preferredGender == "ANY") &&
               (b.preferredGender == a.gender || b.preferredGender == "ANY") &&
               a.ageGroup in (b.minPreferredAge..b.maxPreferredAge) &&
               b.ageGroup in (a.minPreferredAge..a.maxPreferredAge)
    }
}
```

